    63→template <typename KEY_TYPE, typename POOL_TYPE>
    64→bool ConnPoolMap<KEY_TYPE, POOL_TYPE>::erasePool(const KEY_TYPE& key) {
    65→  Common::AutoDebugRecursionChecker assert_not_in(recursion_checker_);
    66→  auto pool_iter = active_pools_.find(key);
    67→
    68→  if (pool_iter != active_pools_.end()) {
    69→    thread_local_dispatcher_.deferredDelete(std::move(pool_iter->second));
    70→    active_pools_.erase(pool_iter);
    71→    host_->cluster().resourceManager(priority_).connectionPools().dec();
    72→    return true;
    73→  } else {
    74→    return false;
    75→  }
    76→}
