   339→std::list<ActiveClientPtr>& ConnPoolImplBase::owningList(ActiveClient::State state) {
   340→  switch (state) {
   341→  case ActiveClient::State::Connecting:
   342→    return connecting_clients_;
   343→  case ActiveClient::State::ReadyForEarlyData:
   344→    return early_data_clients_;
   345→  case ActiveClient::State::Ready:
   346→    return ready_clients_;
   347→  case ActiveClient::State::Busy:
   348→  case ActiveClient::State::Draining:
   349→    return busy_clients_;
   350→  case ActiveClient::State::Closed:
   351→    break; // Fall through to PANIC.
   352→  }
   353→  PANIC("unexpected");
   354→}
