   778→      parent_.host()->cluster().trafficStats()->upstream_cx_length_ms_,
   779→      parent_.dispatcher().timeSource());
   780→  connect_timer_->enableTimer(parent_.host()->cluster().connectTimeout());
   781→  parent_.host()->stats().cx_total_.inc();
   782→  parent_.host()->stats().cx_active_.inc();
   783→  parent_.host()->cluster().trafficStats()->upstream_cx_total_.inc();
   784→  parent_.host()->cluster().trafficStats()->upstream_cx_active_.inc();
   785→  parent_.host()->cluster().resourceManager(parent_.priority()).connections().inc();
